"use client";

import { motion } from "framer-motion";
import { Layers, LayoutTemplate, Server, Brain, Cloud, Database } from "lucide-react";
import { servicesData } from "@/data/portfolio";

export default function ServicesSection() {
  const getIcon = (name: string) => {
    const props = { className: "w-8 h-8" };
    switch (name) {
      case "Layers": return <Layers {...props} />;
      case "LayoutTemplate": return <LayoutTemplate {...props} />;
      case "Server": return <Server {...props} />;
      case "Brain": return <Brain {...props} />;
      case "Cloud": return <Cloud {...props} />;
      case "Database": return <Database {...props} />;
      default: return <Layers {...props} />;
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.15 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, scale: 0.9, y: 30 },
    visible: { opacity: 1, scale: 1, y: 0 },
  };

  return (
    <section id="services" className="py-24 px-4 relative bg-[#0a0a0c]">
      <div className="absolute inset-0 pointer-events-none">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full max-w-4xl max-h-4xl bg-accent-purple/5 rounded-full blur-[120px]" />
      </div>

      <div className="max-w-7xl mx-auto relative z-10">
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
          className="text-center mb-16"
        >
          <h2 className="text-4xl md:text-5xl font-bold mb-4 text-white">
            My <span className="text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-cyan-400">Services</span>
          </h2>
          <div className="w-24 h-1 bg-accent-cyan mx-auto rounded-full mb-6" />
          <p className="text-secondary-gray max-w-2xl mx-auto text-lg">
            Transforming ideas into digital reality with cutting-edge solutions and modern technologies.
          </p>
        </motion.div>

        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          className="grid md:grid-cols-2 lg:grid-cols-3 gap-8"
        >
          {servicesData.map((service, idx) => (
            <motion.div
              key={idx}
              variants={itemVariants}
              whileHover={{ y: -10 }}
              className="group p-8 rounded-2xl bg-gray-900/40 border border-border backdrop-blur-md hover:border-accent-purple transition-all duration-300 flex flex-col h-full shadow-lg hover:shadow-neon"
            >
              <div className="w-16 h-16 rounded-2xl bg-black/50 border border-gray-700 text-accent-purple flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-accent-purple group-hover:text-white transition-all duration-300">
                {getIcon(service.iconName)}
              </div>
              <h3 className="text-xl font-bold text-white mb-4 group-hover:text-accent-cyan transition-colors">
                {service.title}
              </h3>
              <p className="text-secondary-gray leading-relaxed flex-grow mb-8">
                {service.description}
              </p>
              <div className="flex flex-wrap gap-2 mt-auto">
                {service.tags.map((tag, tIdx) => (
                  <span
                    key={tIdx}
                    className="px-3 py-1 rounded-full bg-black/50 text-xs font-medium text-secondary-gray border border-gray-800"
                  >
                    {tag}
                  </span>
                ))}
              </div>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
}
